// data/vignettes.js — GENERATED by pipeline/build-content.js on 2026-07-21. DO NOT EDIT BY HAND.
window.VIGNETTES = [{"id":"va_mdd_cardiac_post_mi_1","stem":"A 64-year-old man develops a major depressive episode 6 weeks after an acute myocardial infarction. He needs an antidepressant with the best cardiac safety evidence in this population. Which is the best choice?","options":["Sertraline","Amitriptyline","Citalopram","Venlafaxine"],"answer":"Sertraline","explanation":"Sertraline is the preferred antidepressant post-MI (SADHART evidence) with a clean cardiac profile. Amitriptyline (TCA) is cardiotoxic and slows conduction, citalopram carries dose-dependent QT prolongation, and venlafaxine raises blood pressure at higher doses.","meds":["sertraline","amitriptyline","citalopram","venlafaxine"],"disorder":"Major depressive disorder","difficulty":2,"tags":["special-population","cardiac","qt","canmat"],"source":{"name":"CANMAT 2016 MDD; SADHART","origin":"canmat"}},{"id":"va_mdd_bulimia_contra_1","stem":"A 24-year-old woman with major depression and active bulimia nervosa needs an antidepressant. Which agent is CONTRAINDICATED?","options":["Bupropion","Fluoxetine","Sertraline","Escitalopram"],"answer":"Bupropion","explanation":"Bupropion lowers the seizure threshold and is contraindicated in eating disorders (bulimia/anorexia) and seizure disorders due to elevated seizure risk. SSRIs are safe here — fluoxetine is in fact the antidepressant of choice for bulimia.","meds":["bupropion","fluoxetine","sertraline","escitalopram"],"disorder":"Major depressive disorder","difficulty":1,"tags":["contraindication","seizure","eating-disorder"],"source":{"name":"Bupropion product monograph (deck)","origin":"monograph"}},{"id":"va_mdd_elderly_mirtazapine_1","stem":"An 80-year-old woman with major depression has prominent insomnia, poor appetite, and 6 kg of weight loss. Which antidepressant best targets her presentation?","options":["Mirtazapine","Bupropion","Fluoxetine","Venlafaxine"],"answer":"Mirtazapine","explanation":"Mirtazapine's H1 antihistamine effect promotes sleep and appetite/weight gain, making it ideal for depressed elderly patients with insomnia and cachexia; 5-HT3 blockade also limits nausea. Bupropion and fluoxetine are activating (worsen insomnia and anorexia), and venlafaxine is not appetite-promoting.","meds":["mirtazapine","bupropion","fluoxetine","venlafaxine"],"disorder":"Major depressive disorder","difficulty":2,"tags":["special-population","elderly"],"source":{"name":"CANMAT 2016 MDD; mirtazapine monograph (deck)","origin":"canmat"}},{"id":"va_mdd_trd_lithium_augment_1","stem":"A 45-year-old with unipolar major depression has not responded to two adequate SSRI/SNRI trials. You want to add an evidence-based augmenting agent that also lowers suicide risk. Best choice?","options":["Lithium","Gabapentin","Buspirone","Diazepam"],"answer":"Lithium","explanation":"Lithium is a classic evidence-based augmentation strategy in treatment-resistant unipolar depression and is the only psychotropic with robust anti-suicide evidence. Gabapentin and benzodiazepines lack antidepressant efficacy; buspirone augmentation is weaker and unrelated to suicide reduction.","meds":["lithium","gabapentin","buspirone","diazepam"],"disorder":"Major depressive disorder","difficulty":2,"tags":["treatment-resistant","augmentation","canmat"],"source":{"name":"CANMAT 2016 MDD; lithium data (deck)","origin":"canmat"}},{"id":"va_mdd_trd_esketamine_1","stem":"A 38-year-old with treatment-resistant depression and acute suicidal ideation needs a rapidly acting option delivered in-clinic under monitoring, paired with an oral antidepressant. Which agent fits?","options":["Esketamine","Sertraline","Amitriptyline","Moclobemide"],"answer":"Esketamine","explanation":"Intranasal esketamine acts within hours and is indicated for treatment-resistant depression and MDD with acute suicidality; it is given in-clinic under a REMS-type program with ≥2 h monitoring and always combined with an oral antidepressant. The oral agents take 2–6 weeks to work.","meds":["esketamine","sertraline","amitriptyline","moclobemide"],"disorder":"Major depressive disorder","difficulty":2,"tags":["treatment-resistant","monitoring"],"source":{"name":"Esketamine monograph (deck)","origin":"monograph"}},{"id":"va_mdd_atypical_maoi_1","stem":"A 34-year-old with recurrent atypical depression — mood reactivity, hypersomnia, hyperphagia, leaden paralysis, and rejection sensitivity — has failed sequential SSRI and SNRI trials. Which agent has the strongest historical evidence for this subtype?","options":["Phenelzine","Bupropion","Nortriptyline","Lithium"],"answer":"Phenelzine","explanation":"Irreversible MAOIs, classically phenelzine, are the historical agents of choice for refractory atypical depression. Before starting, allow the required washout from serotonergic drugs (e.g., 5 weeks after fluoxetine) and counsel on the tyramine diet. TCAs are less effective in atypical depression than MAOIs.","meds":["phenelzine","bupropion","nortriptyline","lithium"],"disorder":"Major depressive disorder","difficulty":3,"tags":["treatment-resistant","washout","serotonin"],"source":{"name":"CANMAT 2016 MDD; phenelzine monograph (deck)","origin":"canmat"}},{"id":"va_gad_first_line_1","stem":"A 29-year-old with newly diagnosed generalized anxiety disorder and no substance-use history wants first-line pharmacotherapy. Best initial choice?","options":["Escitalopram","Alprazolam","Buspirone","Quetiapine"],"answer":"Escitalopram","explanation":"An SSRI (escitalopram) is first-line for GAD — effective, well tolerated, and non-dependence-forming. Benzodiazepines like alprazolam risk tolerance/dependence and are not first-line maintenance; buspirone is a second-line/augmenting option; quetiapine is off-label with a heavy side-effect burden.","meds":["escitalopram","alprazolam","buspirone","quetiapine"],"disorder":"Generalized anxiety disorder","difficulty":1,"tags":["first-line","canmat"],"source":{"name":"Canadian Anxiety Guidelines 2014","origin":"canmat"}},{"id":"va_gad_sud_buspirone_1","stem":"A 41-year-old with generalized anxiety disorder and active alcohol use disorder needs an anxiolytic with no abuse or dependence potential. Which is most appropriate?","options":["Buspirone","Diazepam","Lorazepam","Alprazolam"],"answer":"Buspirone","explanation":"Buspirone (5-HT1A partial agonist) has no dependence or abuse potential and is a preferred anxiolytic in patients with a substance-use history; it must be taken daily and takes ~2 weeks to work. The benzodiazepines all carry dependence risk and are hazardous in active alcohol use disorder.","meds":["buspirone","diazepam","lorazepam","alprazolam"],"disorder":"Generalized anxiety disorder","difficulty":2,"tags":["special-population","substance-use"],"source":{"name":"Buspirone monograph (deck)","origin":"monograph"}},{"id":"va_panic_first_line_1","stem":"A 31-year-old with panic disorder wants maintenance pharmacotherapy. Which is the best first-line long-term agent (started low and titrated slowly)?","options":["Sertraline","Alprazolam","Bupropion","Propranolol"],"answer":"Sertraline","explanation":"SSRIs such as sertraline are first-line for panic disorder; start low and go slow because initial activation can transiently worsen panic. Alprazolam works acutely but risks dependence and is not preferred for maintenance; bupropion is activating and not indicated; propranolol does not treat panic disorder.","meds":["sertraline","alprazolam","bupropion","propranolol"],"disorder":"Panic disorder","difficulty":1,"tags":["first-line","canmat"],"source":{"name":"Canadian Anxiety Guidelines 2014","origin":"canmat"}},{"id":"va_ocd_first_line_1","stem":"A 27-year-old with obsessive-compulsive disorder is starting pharmacotherapy. Which is an appropriate first-line agent, recognizing OCD often needs higher doses and a longer trial?","options":["Fluvoxamine","Bupropion","Nortriptyline","Lithium"],"answer":"Fluvoxamine","explanation":"SSRIs are first-line for OCD, often at higher doses and with a 10–12 week trial; fluvoxamine is a go-to agent. Bupropion (NDRI) and nortriptyline (a noradrenergic TCA) lack anti-obsessional efficacy, and lithium is not a primary OCD treatment.","meds":["fluvoxamine","bupropion","nortriptyline","lithium"],"disorder":"Obsessive-compulsive disorder","difficulty":1,"tags":["first-line","canmat"],"source":{"name":"Canadian Anxiety Guidelines 2014","origin":"canmat"}},{"id":"va_ocd_clomipramine_1","stem":"A 33-year-old with severe OCD has failed adequate trials of three different SSRIs. Which agent has the strongest evidence as the next step?","options":["Clomipramine","Amitriptyline","Desipramine","Imipramine"],"answer":"Clomipramine","explanation":"Clomipramine, the most serotonergic TCA, is the historical gold-standard for OCD and the only TCA with robust anti-obsessional efficacy — the classic choice after SSRI failure. The other TCAs are more noradrenergic and ineffective for OCD; watch clomipramine's dose-dependent seizure risk (250 mg/day ceiling).","meds":["clomipramine","amitriptyline","desipramine","imipramine"],"disorder":"Obsessive-compulsive disorder","difficulty":2,"tags":["treatment-resistant","seizure"],"source":{"name":"Clomipramine monograph (deck)","origin":"monograph"}},{"id":"va_ptsd_first_line_1","stem":"A 36-year-old veteran with PTSD is starting pharmacotherapy alongside trauma-focused psychotherapy. Which is an appropriate first-line medication?","options":["Sertraline","Alprazolam","Bupropion","Lithium"],"answer":"Sertraline","explanation":"SSRIs (sertraline, paroxetine) are first-line for PTSD. Benzodiazepines such as alprazolam are specifically discouraged — they do not treat core PTSD symptoms, may impair fear extinction, and carry dependence risk in a high-comorbidity population. Bupropion and lithium are not PTSD treatments.","meds":["sertraline","alprazolam","bupropion","lithium"],"disorder":"Post-traumatic stress disorder","difficulty":1,"tags":["first-line","canmat"],"source":{"name":"Canadian Anxiety Guidelines 2014","origin":"canmat"}},{"id":"va_ptsd_prazosin_1","stem":"A 44-year-old with PTSD is stable on an SSRI but has disabling recurrent trauma nightmares and fragmented sleep. Which adjunct specifically targets this symptom?","options":["Prazosin","Zopiclone","Quetiapine","Clonazepam"],"answer":"Prazosin","explanation":"Prazosin, an α1-antagonist dosed at bedtime, is the off-label go-to for PTSD-associated nightmares and trauma-related sleep disruption. Warn about the first-dose orthostatic hypotension/syncope and start at 1 mg. Z-drugs, quetiapine, and benzodiazepines do not selectively address trauma nightmares.","meds":["prazosin","zopiclone","quetiapine","clonazepam"],"disorder":"Post-traumatic stress disorder","difficulty":2,"tags":["special-population","adjunct"],"source":{"name":"Prazosin monograph (deck)","origin":"monograph"}},{"id":"va_social_generalized_first_line_1","stem":"A 25-year-old with generalized social anxiety disorder (pervasive fear across most social situations) wants ongoing pharmacotherapy. Best first-line choice?","options":["Paroxetine","Propranolol","Buspirone","Amitriptyline"],"answer":"Paroxetine","explanation":"SSRIs/SNRIs (e.g., paroxetine) are first-line for generalized social anxiety disorder. Propranolol helps only discrete performance (situational) anxiety, not the generalized subtype; buspirone is not established for SAD; and amitriptyline (TCA) is not a first-line anxiety agent.","meds":["paroxetine","propranolol","buspirone","amitriptyline"],"disorder":"Social anxiety disorder","difficulty":1,"tags":["first-line","canmat"],"source":{"name":"Canadian Anxiety Guidelines 2014","origin":"canmat"}},{"id":"va_social_performance_propranolol_1","stem":"A 30-year-old violinist has isolated performance anxiety — palpitations, tremor, and sweating only when playing on stage — and wants an as-needed agent for the physical symptoms. Which is most appropriate?","options":["Propranolol","Sertraline","Buspirone","Clonazepam"],"answer":"Propranolol","explanation":"For discrete performance (situational) social anxiety, a PRN beta-blocker such as propranolol blunts the autonomic symptoms (tremor, palpitations) without sedation or dependence. SSRIs are for generalized SAD and take weeks; a benzodiazepine risks dependence and impairs fine motor performance.","meds":["propranolol","sertraline","buspirone","clonazepam"],"disorder":"Social anxiety disorder","difficulty":2,"tags":["performance","adjunct"],"source":{"name":"Propranolol monograph (deck)","origin":"monograph"}},{"id":"va_bipolar_mania_lithium_1","stem":"A 26-year-old man with bipolar I disorder presents with a first euphoric manic episode and a strong family history of good lithium response. You want a first-line monotherapy that also reduces long-term suicide risk. Best choice?","options":["Lithium","Lamotrigine","Bupropion","Sertraline"],"answer":"Lithium","explanation":"Lithium is CANMAT/ISBD first-line for acute mania and maintenance and uniquely reduces suicide risk, with a good family-history predictor of response. Lamotrigine is ineffective for acute mania, and antidepressants (bupropion, sertraline) can precipitate or worsen mania.","meds":["lithium","lamotrigine","bupropion","sertraline"],"disorder":"Bipolar I disorder","difficulty":1,"tags":["first-line","mania","canmat"],"source":{"name":"CANMAT/ISBD 2018 Bipolar Guidelines","origin":"canmat"}},{"id":"va_bipolar_depression_lurasidone_1","stem":"A 40-year-old with bipolar I disorder presents in an acute bipolar depressive episode and you want first-line monotherapy with a favourable metabolic profile. Which is an appropriate choice?","options":["Lurasidone","Fluoxetine","Diazepam","Carbamazepine"],"answer":"Lurasidone","explanation":"Lurasidone is CANMAT/ISBD first-line for acute bipolar depression and is relatively metabolically favourable. Antidepressant monotherapy (fluoxetine) is avoided in bipolar depression (mood-switch/cycling risk), a benzodiazepine does not treat the depression, and carbamazepine is not a first-line agent for the depressive pole.","meds":["lurasidone","fluoxetine","diazepam","carbamazepine"],"disorder":"Bipolar I disorder","difficulty":2,"tags":["first-line","bipolar-depression","canmat"],"source":{"name":"CANMAT/ISBD 2018 Bipolar Guidelines","origin":"canmat"}},{"id":"va_bipolar_maintenance_lamotrigine_1","stem":"A 35-year-old with bipolar II disorder has predominantly recurrent depressive episodes and few hypomanias. Which agent is best for maintenance to prevent depressive relapse?","options":["Lamotrigine","Valproate / Divalproex","Haloperidol","Bupropion"],"answer":"Lamotrigine","explanation":"Lamotrigine is first-line for bipolar maintenance with predominant depressive polarity — it prevents depressive relapse but is not effective for acute mania. Titrate slowly to avoid SJS/TEN. Valproate targets the manic pole, haloperidol is not a maintenance mood-stabilizer of choice here, and antidepressant monotherapy is inappropriate in bipolar disorder.","meds":["lamotrigine","valproate","haloperidol","bupropion"],"disorder":"Bipolar II disorder","difficulty":2,"tags":["maintenance","canmat"],"source":{"name":"CANMAT/ISBD 2018 Bipolar Guidelines","origin":"canmat"}},{"id":"va_bipolar_pregnancy_valproate_1","stem":"A 28-year-old woman with bipolar disorder who is planning pregnancy asks which mood stabilizer should be AVOIDED because of the highest teratogenic risk. Which agent?","options":["Valproate / Divalproex","Lamotrigine","Quetiapine","Lithium"],"answer":"Valproate / Divalproex","explanation":"Valproate carries the highest teratogenic risk — neural tube defects and impaired neurodevelopment/IQ — and is avoided in anyone who could become pregnant. Lamotrigine and quetiapine are comparatively safer options; lithium carries an Ebstein-anomaly signal but a much lower absolute risk than valproate.","meds":["valproate","lamotrigine","quetiapine","lithium"],"disorder":"Bipolar I disorder","difficulty":2,"tags":["special-population","pregnancy","contraindication"],"source":{"name":"CANMAT/ISBD 2018 Bipolar Guidelines","origin":"canmat"}},{"id":"va_serotonin_syndrome_1","stem":"A 52-year-old on phenelzine is inadvertently started on sertraline. Within a day he develops agitation, diaphoresis, hyperthermia, and lower-limb clonus with hyperreflexia. What is the diagnosis?","options":["Serotonin syndrome","Neuroleptic malignant syndrome","Anticholinergic toxicity","Lithium toxicity"],"answer":"Serotonin syndrome","explanation":"Combining an MAOI with an SSRI causes serotonin syndrome — the triad of neuromuscular excitability (clonus, hyperreflexia), autonomic instability, and altered mental status. Clonus/hyperreflexia distinguish it from NMS (rigidity, hyporeflexia, slower onset). This is why a strict washout is mandatory between MAOIs and serotonergic drugs.","meds":["phenelzine","sertraline"],"disorder":"Serotonin syndrome","difficulty":2,"tags":["serotonin","interaction","washout"],"source":{"name":"Phenelzine/sertraline interactions (deck)","origin":"openfda"}},{"id":"va_maoi_tyramine_crisis_1","stem":"A 49-year-old on tranylcypromine eats aged cheese and cured meats at a party and rapidly develops a severe throbbing occipital headache, palpitations, and a blood pressure of 210/120. What is the diagnosis?","options":["Tyramine (hypertensive) crisis","Serotonin syndrome","Anticholinergic toxicity","Neuroleptic malignant syndrome"],"answer":"Tyramine (hypertensive) crisis","explanation":"Irreversible MAOIs block gut/hepatic MAO, so dietary tyramine triggers a surge of noradrenaline release — a hypertensive crisis with occipital headache and palpitations. This is why a strict low-tyramine diet is required. The reversible RIMA moclobemide avoids this because tyramine can displace it from MAO-A.","meds":["tranylcypromine","moclobemide"],"disorder":"Major depressive disorder","difficulty":2,"tags":["hypertensive-crisis","interaction","diet"],"source":{"name":"Tranylcypromine/MAOI diet (deck)","origin":"monograph"}},{"id":"va_lithium_toxicity_1","stem":"A 72-year-old woman stable on lithium is started on lisinopril for hypertension and then develops gastroenteritis with poor oral intake. She now has a coarse tremor, ataxia, slurred speech, and confusion. What is the diagnosis?","options":["Lithium toxicity","Serotonin syndrome","Neuroleptic malignant syndrome","Anticholinergic toxicity"],"answer":"Lithium toxicity","explanation":"ACE inhibitors and volume depletion reduce renal lithium clearance and raise the level; coarse tremor, ataxia, dysarthria, and confusion are hallmark toxicity signs (worse in the elderly with reduced renal reserve). NSAIDs, thiazides, ARBs, and dehydration act the same way — lithium has a narrow therapeutic index (toxic >1.5 mmol/L).","meds":["lithium"],"disorder":"Bipolar I disorder","difficulty":2,"tags":["overdose","interaction","elderly","monitoring"],"source":{"name":"Lithium interactions/warnings (deck)","origin":"openfda"}},{"id":"vp_scz_first_line_metabolic","stem":"A 23-year-old man with a first episode of schizophrenia, no prior antipsychotic exposure and a family history of type 2 diabetes, is anxious about weight gain. Which agent best balances efficacy with a weight- and prolactin-neutral profile as an initial choice?","options":["Aripiprazole","Olanzapine","Clozapine","Chlorpromazine"],"answer":"Aripiprazole","explanation":"Aripiprazole is a D2 partial agonist that is essentially weight- and prolactin-neutral, making it a sensible first-episode choice when metabolic risk matters. Olanzapine has the worst metabolic burden of the mainstream SGAs; clozapine is reserved for treatment resistance; chlorpromazine is a sedating, anticholinergic low-potency FGA.","meds":["aripiprazole","olanzapine","clozapine","chlorpromazine"],"disorder":"Schizophrenia","difficulty":1,"tags":["first-line","metabolic"],"source":{"name":"CPA Schizophrenia Guidelines","origin":"authored"}},{"id":"vp_scz_trs_clozapine","stem":"A 29-year-old with schizophrenia has had persistent positive symptoms despite adequate trials (dose and duration) of risperidone and then olanzapine. Adherence is confirmed. What is the next best pharmacologic step?","options":["Clozapine","Haloperidol","Quetiapine","Benztropine"],"answer":"Clozapine","explanation":"Failure of two adequate antipsychotic trials defines treatment-resistant schizophrenia, for which clozapine is the only agent with proven superior efficacy (and the only one shown to reduce suicidality). Switching to another standard antipsychotic or adding an anticholinergic does not address resistance.","meds":["clozapine","risperidone","olanzapine","haloperidol","quetiapine","benztropine"],"disorder":"Schizophrenia","difficulty":1,"tags":["treatment-resistant","clozapine"],"source":{"name":"Clozapine monograph / CPA Schizophrenia Guidelines","origin":"monograph"}},{"id":"vp_scz_clozapine_myocarditis","stem":"A patient in the third week of clozapine titration develops fever, pleuritic chest pain, tachycardia, and a rising troponin and CRP. Which clozapine-associated complication is most likely?","options":["Myocarditis","Neuroleptic malignant syndrome","Agranulocytosis","Pulmonary embolism"],"answer":"Myocarditis","explanation":"Clozapine-induced myocarditis clusters in the first 6–8 weeks and presents with fever, chest pain, tachycardia, and rising troponin/CRP (± eosinophilia). It is distinct from the blood dyscrasia (agranulocytosis) and from NMS, and warrants stopping clozapine.","meds":["clozapine"],"disorder":"Schizophrenia","difficulty":2,"tags":["clozapine","syndrome-id"],"source":{"name":"Clozapine boxed warning / monograph","origin":"monograph"}},{"id":"vp_scz_clozapine_agranulocytosis","stem":"A patient on clozapine for 8 weeks presents with fever and a severe sore throat. The absolute neutrophil count is 300/µL. Which adverse effect does this represent?","options":["Agranulocytosis","Neuroleptic malignant syndrome","Myocarditis","Metabolic syndrome"],"answer":"Agranulocytosis","explanation":"An ANC of 300/µL is severe neutropenia/agranulocytosis — clozapine must be stopped immediately (and not rechallenged) with hematology involvement, because of the risk of fatal infection. This mandatory ANC monitoring is why clozapine is reserved despite its efficacy.","meds":["clozapine"],"disorder":"Schizophrenia","difficulty":2,"tags":["clozapine","agranulocytosis","syndrome-id"],"source":{"name":"Clozapine boxed warning / monograph","origin":"monograph"}},{"id":"vp_scz_clozapine_fluvoxamine","stem":"A patient stable on clozapine needs an antidepressant added for comorbid depression. Which co-prescription is most likely to raise clozapine levels and precipitate toxicity (sedation, seizures)?","options":["Fluvoxamine","Sertraline","Escitalopram","Bupropion"],"answer":"Fluvoxamine","explanation":"Fluvoxamine is a potent CYP1A2 inhibitor and clozapine is a major CYP1A2 substrate, so co-prescription can markedly increase clozapine levels and seizure/toxicity risk. (Conversely, smoking cessation removes CYP1A2 induction and also raises levels.)","meds":["clozapine","fluvoxamine","sertraline","escitalopram","bupropion"],"disorder":"Schizophrenia","difficulty":3,"tags":["clozapine","interaction"],"source":{"name":"Clozapine monograph (CYP1A2 interactions)","origin":"monograph"}},{"id":"vp_scz_metabolic_diabetes","stem":"A 45-year-old with schizophrenia has obesity and poorly controlled type 2 diabetes. You want maintenance antipsychotic therapy with the least metabolic impact. Which is most appropriate?","options":["Lurasidone","Olanzapine","Clozapine","Chlorpromazine"],"answer":"Lurasidone","explanation":"Lurasidone is among the most metabolically favourable SGAs (largely weight-, lipid-, and glucose-neutral) — remembering it must be taken with ≥350 kcal of food for absorption. Olanzapine and clozapine carry the highest metabolic burden, and low-potency FGAs like chlorpromazine also cause weight gain.","meds":["lurasidone","olanzapine","clozapine","chlorpromazine"],"disorder":"Schizophrenia","difficulty":2,"tags":["metabolic"],"source":{"name":"Lurasidone monograph","origin":"monograph"}},{"id":"vp_scz_lai_adherence","stem":"A 34-year-old with schizophrenia has had three relapse hospitalizations driven by covert non-adherence to oral medication. He responds to and tolerates an SGA. What is the best strategy to improve adherence?","options":["Paliperidone","Quetiapine","Lurasidone","Clozapine"],"answer":"Paliperidone","explanation":"Paliperidone palmitate is a long-acting injectable, directly addressing covert non-adherence and reducing relapse. Quetiapine, lurasidone, and clozapine are oral-only in Canada (clozapine is also reserved for treatment resistance).","meds":["paliperidone","quetiapine","lurasidone","clozapine"],"disorder":"Schizophrenia","difficulty":2,"tags":["lai","adherence"],"source":{"name":"Paliperidone palmitate monograph","origin":"monograph"}},{"id":"vp_agit_olanzapine_benzo","stem":"An acutely agitated psychotic patient in the emergency department is being managed with intramuscular medication. Co-administering a parenteral benzodiazepine with which antipsychotic carries a specific risk of cardiorespiratory depression and should be avoided?","options":["Olanzapine","Haloperidol","Ziprasidone","Aripiprazole"],"answer":"Olanzapine","explanation":"Intramuscular olanzapine combined with a parenteral benzodiazepine has caused excessive sedation and cardiorespiratory depression, so the combination is avoided (separate the doses). IM haloperidol is routinely combined with lorazepam, and the other agents do not carry this specific warning.","meds":["olanzapine","haloperidol","ziprasidone","aripiprazole","lorazepam"],"disorder":"Acute agitation","difficulty":2,"tags":["agitation","interaction"],"source":{"name":"Olanzapine monograph (IM warning)","origin":"monograph"}},{"id":"vp_delirium_haloperidol","stem":"An 80-year-old post-operative patient has hyperactive delirium with severe agitation that threatens lines and safety despite non-pharmacologic measures. Which pharmacologic agent is most appropriate for short-term control?","options":["Haloperidol","Lorazepam","Quetiapine","Chlorpromazine"],"answer":"Haloperidol","explanation":"When medication is unavoidable for dangerous agitation in delirium, a low-dose high-potency antipsychotic such as haloperidol is preferred. Benzodiazepines can worsen or prolong delirium (reserved for alcohol/sedative withdrawal), and chlorpromazine's hypotension and anticholinergic load are poorly tolerated in the elderly.","meds":["haloperidol","lorazepam","quetiapine","chlorpromazine"],"disorder":"Delirium","difficulty":2,"tags":["delirium","elderly"],"source":{"name":"Delirium management (authored)","origin":"authored"}},{"id":"vp_delirium_etoh_withdrawal","stem":"A 55-year-old admitted 48 hours after his last drink becomes agitated and confused with tremor, diaphoresis, tachycardia, and hypertension. Which is the first-line pharmacologic treatment for this delirium?","options":["Lorazepam","Haloperidol","Olanzapine","Risperidone"],"answer":"Lorazepam","explanation":"This is alcohol-withdrawal delirium (delirium tremens), for which a benzodiazepine such as lorazepam is first-line and lifesaving. Antipsychotics lower the seizure threshold and are only adjuncts here — the opposite of the approach to a general medical/post-operative delirium.","meds":["lorazepam","haloperidol","olanzapine","risperidone"],"disorder":"Delirium","difficulty":2,"tags":["delirium","withdrawal"],"source":{"name":"Alcohol withdrawal management (authored)","origin":"authored"}},{"id":"vp_bpsd_risperidone","stem":"An 82-year-old with Alzheimer dementia has persistent aggression and psychosis endangering caregivers despite behavioural interventions. After discussing the increased mortality risk, a short low-dose antipsychotic trial is chosen. Which agent has the best evidence for short-term severe aggression in dementia?","options":["Risperidone","Clozapine","Ziprasidone","Chlorpromazine"],"answer":"Risperidone","explanation":"Low-dose risperidone is the best-studied option (with a limited short-term indication for severe aggression) in dementia, though all antipsychotics carry a boxed warning for increased mortality and cerebrovascular events — use the lowest dose for the shortest time. Clozapine (agranulocytosis monitoring) and sedating/anticholinergic FGAs are inappropriate in this population.","meds":["risperidone","clozapine","ziprasidone","chlorpromazine"],"disorder":"Major neurocognitive disorder (dementia)","difficulty":2,"tags":["bpsd","elderly"],"source":{"name":"Risperidone monograph (dementia warning)","origin":"monograph"}},{"id":"vp_pd_psychosis_pimavanserin","stem":"A 74-year-old with Parkinson disease develops distressing visual hallucinations. Dopaminergic therapy is already minimized. Which agent treats the psychosis with the least risk of worsening his motor symptoms?","options":["Pimavanserin","Haloperidol","Risperidone","Olanzapine"],"answer":"Pimavanserin","explanation":"Pimavanserin is a selective 5-HT2A inverse agonist with no D2 blockade, so it treats Parkinson-disease psychosis without worsening motor function (low-dose quetiapine or clozapine are the usual Canadian alternatives). D2 blockers such as haloperidol, risperidone, and olanzapine aggravate parkinsonism and are avoided.","meds":["pimavanserin","haloperidol","risperidone","olanzapine","quetiapine","clozapine"],"disorder":"Parkinson disease psychosis","difficulty":3,"tags":["pd-psychosis","eps"],"source":{"name":"Pimavanserin monograph","origin":"monograph"}},{"id":"vp_eps_acute_dystonia_tx","stem":"A 19-year-old man given intramuscular haloperidol for agitation develops, a few hours later, painful neck twisting (torticollis) and an upward fixed gaze (oculogyric crisis). What is the best immediate treatment?","options":["Benztropine","Propranolol","Tetrabenazine","Valbenazine"],"answer":"Benztropine","explanation":"Acute dystonia (young men, high-potency FGAs, within hours) responds rapidly to an intramuscular anticholinergic such as benztropine (or diphenhydramine). Propranolol treats akathisia, and VMAT2 inhibitors (tetrabenazine, valbenazine) are for tardive dyskinesia.","meds":["benztropine","propranolol","tetrabenazine","valbenazine","haloperidol"],"disorder":"Extrapyramidal symptoms","difficulty":1,"tags":["eps","dystonia"],"source":{"name":"Benztropine monograph","origin":"monograph"}},{"id":"vp_eps_dystonia_syndrome_id","stem":"Hours after his first dose of a high-potency antipsychotic, a young patient develops sustained involuntary contraction of the neck and jaw muscles with an upward eye deviation. Which movement syndrome is this?","options":["Acute dystonia","Tardive dyskinesia","Akathisia","Neuroleptic malignant syndrome"],"answer":"Acute dystonia","explanation":"Sustained, painful muscle contractions (torticollis, oculogyric crisis, trismus, potentially laryngospasm) appearing within hours to days of a D2 blocker define acute dystonia. It is distinct from the choreoathetoid movements of tardive dyskinesia, the restlessness of akathisia, and the rigidity/fever of NMS.","meds":["haloperidol","benztropine"],"disorder":"Extrapyramidal symptoms","difficulty":2,"tags":["eps","dystonia","syndrome-id"],"source":{"name":"EPS recognition (authored)","origin":"authored"}},{"id":"vp_eps_akathisia_propranolol","stem":"One week after starting an antipsychotic, a patient reports an intolerable inner restlessness and an inability to sit still, and is observed pacing and shifting constantly. After considering a dose reduction, which is the best-evidenced pharmacologic treatment?","options":["Propranolol","Benztropine","Tetrabenazine","Amantadine"],"answer":"Propranolol","explanation":"Antipsychotic-induced akathisia responds best to a beta-blocker such as propranolol (± lowering the antipsychotic dose or a short benzodiazepine course). Anticholinergics like benztropine do not reliably relieve akathisia, and dopamine-depleting VMAT2 inhibitors are for tardive dyskinesia.","meds":["propranolol","benztropine","tetrabenazine","amantadine"],"disorder":"Extrapyramidal symptoms","difficulty":2,"tags":["eps","akathisia"],"source":{"name":"Propranolol monograph","origin":"monograph"}},{"id":"vp_eps_td_syndrome_id","stem":"A 68-year-old who has taken an antipsychotic for several years develops persistent involuntary lip-smacking, tongue protrusion, and choreoathetoid facial movements that are absent during sleep. Which syndrome is this?","options":["Tardive dyskinesia","Acute dystonia","Akathisia","Drug-induced parkinsonism"],"answer":"Tardive dyskinesia","explanation":"Late-onset, repetitive orofacial-lingual choreoathetoid movements after prolonged D2 blockade define tardive dyskinesia. It contrasts with the acute sustained spasm of dystonia, the subjective restlessness of akathisia, and the bradykinesia/rigidity/tremor of drug-induced parkinsonism.","meds":["haloperidol","tetrabenazine"],"disorder":"Tardive dyskinesia","difficulty":2,"tags":["eps","tardive-dyskinesia","syndrome-id"],"source":{"name":"EPS recognition (authored)","origin":"authored"}},{"id":"vp_eps_td_tx","stem":"A patient has established tardive dyskinesia with troublesome orofacial movements after years of antipsychotic therapy. Which class of agent is the evidence-based treatment?","options":["Tetrabenazine","Benztropine","Trihexyphenidyl","Propranolol"],"answer":"Tetrabenazine","explanation":"Tardive dyskinesia is treated with a VMAT2 inhibitor — tetrabenazine is the Canada-available option (the purpose-built agents valbenazine and deutetrabenazine are US-approved for TD). Anticholinergics such as benztropine and trihexyphenidyl actually WORSEN tardive dyskinesia, and propranolol targets akathisia.","meds":["tetrabenazine","benztropine","trihexyphenidyl","propranolol","valbenazine","deutetrabenazine"],"disorder":"Tardive dyskinesia","difficulty":2,"tags":["eps","tardive-dyskinesia"],"source":{"name":"Tetrabenazine monograph","origin":"monograph"}},{"id":"vp_eps_parkinsonism_amantadine","stem":"A patient on an antipsychotic develops bradykinesia, cogwheel rigidity, and a resting tremor consistent with drug-induced parkinsonism. Antipsychotic dose reduction is not fully sufficient. Which adjunct is appropriate, and which class must be avoided because it would worsen the picture?","options":["Amantadine","Tetrabenazine","Valbenazine","Propranolol"],"answer":"Amantadine","explanation":"Drug-induced parkinsonism is managed by reducing/switching the antipsychotic and, if needed, an anticholinergic or the dopaminergic agent amantadine. VMAT2 inhibitors (tetrabenazine, valbenazine) deplete dopamine and would aggravate parkinsonism, and propranolol does not treat it.","meds":["amantadine","tetrabenazine","valbenazine","propranolol"],"disorder":"Extrapyramidal symptoms","difficulty":2,"tags":["eps","parkinsonism"],"source":{"name":"Amantadine monograph","origin":"monograph"}},{"id":"vp_nms_recognition","stem":"Three days after starting haloperidol, a patient develops a temperature of 40°C, generalized 'lead-pipe' rigidity, fluctuating consciousness, labile blood pressure and tachycardia, and a markedly elevated creatine kinase. What is the diagnosis?","options":["Neuroleptic malignant syndrome","Serotonin syndrome","Malignant hyperthermia","Anticholinergic toxicity"],"answer":"Neuroleptic malignant syndrome","explanation":"Hyperthermia, lead-pipe rigidity, altered mental status, autonomic instability, and a high CK developing over days after a D2 blocker are the classic tetrad of NMS. Serotonin syndrome instead shows clonus/hyperreflexia with rapid onset after serotonergic drugs; anticholinergic toxicity gives dry, flushed skin without rigidity or CK elevation.","meds":["haloperidol"],"disorder":"Neuroleptic malignant syndrome","difficulty":2,"tags":["nms","syndrome-id"],"source":{"name":"NMS recognition (authored)","origin":"authored"}},{"id":"vp_nms_culprit","stem":"Which of the following antipsychotics carries the highest risk of precipitating neuroleptic malignant syndrome?","options":["Haloperidol","Quetiapine","Clozapine","Aripiprazole"],"answer":"Haloperidol","explanation":"NMS risk rises with potent, tight D2 blockade, so high-potency FGAs such as haloperidol carry the greatest risk (especially with rapid dose escalation or parenteral use). Loosely-binding or partial-agonist agents like quetiapine, clozapine, and aripiprazole carry lower — though not zero — risk.","meds":["haloperidol","quetiapine","clozapine","aripiprazole"],"disorder":"Neuroleptic malignant syndrome","difficulty":2,"tags":["nms"],"source":{"name":"Antipsychotic monographs (NMS)","origin":"monograph"}},{"id":"vp_hyperprolactinemia_switch","stem":"A 26-year-old woman on risperidone develops amenorrhea and galactorrhea; her prolactin is markedly elevated with no pituitary lesion on imaging. Which switch best addresses the hyperprolactinemia?","options":["Aripiprazole","Paliperidone","Haloperidol","Fluphenazine"],"answer":"Aripiprazole","explanation":"Risperidone (and its metabolite paliperidone) cause the most marked hyperprolactinemia among antipsychotics. Switching to the prolactin-sparing partial agonist aripiprazole typically normalizes prolactin, whereas high-potency FGAs like haloperidol and fluphenazine raise it further.","meds":["aripiprazole","paliperidone","haloperidol","fluphenazine","risperidone"],"disorder":"Schizophrenia","difficulty":2,"tags":["hyperprolactinemia"],"source":{"name":"Aripiprazole / risperidone monographs","origin":"monograph"}},{"id":"vp_qt_ziprasidone","stem":"A patient with congenital long-QT syndrome and a baseline QTc of 480 ms needs an antipsychotic. Which agent is most important to AVOID because it carries the greatest QT-prolonging risk among the SGAs?","options":["Ziprasidone","Aripiprazole","Lurasidone","Brexpiprazole"],"answer":"Ziprasidone","explanation":"Ziprasidone produces the greatest QTc prolongation of the SGAs and should be avoided when the QT is already long. Aripiprazole, lurasidone, and brexpiprazole are comparatively QT-neutral and are safer choices in this setting.","meds":["ziprasidone","aripiprazole","lurasidone","brexpiprazole"],"disorder":"Schizophrenia","difficulty":2,"tags":["qt"],"source":{"name":"Ziprasidone monograph","origin":"monograph"}},{"id":"vt_recognise_serotonin_syndrome_1","stem":"A 40-year-old on sertraline for depression is given tramadol for back pain. Over ~12 hours he develops agitation, diaphoresis, tachycardia, hyperthermia, and — on exam — inducible lower-limb clonus and hyperreflexia worse in the legs. Most likely syndrome?","options":["Serotonin syndrome","Neuroleptic malignant syndrome","Anticholinergic toxicity","Lithium toxicity"],"answer":"Serotonin syndrome","explanation":"Rapid onset (hours) with NEUROMUSCULAR EXCITABILITY — clonus and hyperreflexia, lower-limb predominant — after adding a second serotonergic (tramadol to an SSRI) is the signature of serotonin syndrome. NMS instead evolves over days with lead-pipe rigidity and hyporeflexia; anticholinergic toxicity gives dry skin and normal reflexes; lithium toxicity gives a coarse tremor and ataxia, not clonus.","meds":["sertraline"],"disorder":"Serotonin syndrome","difficulty":2,"tags":["serotonin","interaction"],"source":{"name":"FRCPC toxidrome recognition (Hunter criteria)","origin":"authored"}},{"id":"vt_recognise_nms_1","stem":"A 28-year-old admitted with mania is started on haloperidol. Four days later he is febrile (39.5°C), profoundly diaphoretic, with generalised 'lead-pipe' rigidity, hyporeflexia, fluctuating consciousness, labile blood pressure, and CK 6000. Most likely syndrome?","options":["Neuroleptic malignant syndrome","Serotonin syndrome","Anticholinergic toxicity","Hypertensive crisis (tyramine reaction)"],"answer":"Neuroleptic malignant syndrome","explanation":"Sub-acute onset (days) after a dopamine antagonist, with lead-pipe rigidity, HYPOreflexia, hyperthermia, autonomic instability, and markedly elevated CK, defines NMS. Serotonin syndrome is faster and features clonus/hyperreflexia rather than hyporeflexia; anticholinergic toxicity lacks rigidity and CK rise; a tyramine reaction is an acute hypertensive event without rigidity.","meds":["haloperidol"],"disorder":"Neuroleptic malignant syndrome","difficulty":2,"tags":["nms"],"source":{"name":"FRCPC toxidrome recognition","origin":"authored"}},{"id":"vt_ss_vs_nms_discriminator_1","stem":"A patient stabilised on olanzapine has sertraline added 2 days ago and now presents with hyperthermia, agitation, tremor, and — critically — spontaneous ocular clonus and brisk hyperreflexia rather than rigidity. Which single exam finding best distinguishes his diagnosis from neuroleptic malignant syndrome?","options":["Serotonin syndrome","Neuroleptic malignant syndrome","Anticholinergic toxicity","Lithium toxicity"],"answer":"Serotonin syndrome","explanation":"Clonus and hyperreflexia point to serotonin syndrome (here precipitated by the newly added serotonergic), whereas NMS produces lead-pipe RIGIDITY with hyporeflexia. Onset also helps: serotonin syndrome is hours, NMS is days. The distinction drives management — cyproheptadine and stopping serotonergics versus dantrolene/bromocriptine and stopping the antipsychotic.","meds":["sertraline","olanzapine"],"disorder":"Serotonin syndrome","difficulty":3,"tags":["serotonin","nms","interaction"],"source":{"name":"FRCPC toxidrome discriminator","origin":"authored"}},{"id":"vt_recognise_anticholinergic_toxidrome_1","stem":"A 19-year-old is brought in after ingesting a bottle of amitriptyline. She is delirious and agitated with dilated pupils, dry flushed skin, absent bowel sounds, urinary retention, and tachycardia; the ECG shows a widening QRS. Which toxidrome best explains the peripheral findings?","options":["Anticholinergic toxicity","Serotonin syndrome","Neuroleptic malignant syndrome","Lithium toxicity"],"answer":"Anticholinergic toxicity","explanation":"The classic anticholinergic toxidrome — 'mad, blind, dry, red, hot, and full' (delirium, mydriasis, dry/flushed skin, ileus, urinary retention, hyperthermia) — is prominent in TCA overdose. Note the co-existing life-threat: Na-channel-blockade cardiotoxicity (wide QRS) is what actually kills in amitriptyline overdose and is treated with IV sodium bicarbonate for QRS >100 ms.","meds":["amitriptyline"],"disorder":"Anticholinergic toxicity","difficulty":2,"tags":["overdose"],"source":{"name":"Amitriptyline monograph — overdose","origin":"monograph"}},{"id":"vt_recognise_lithium_toxicity_1","stem":"A 55-year-old on long-term lithium for bipolar I develops a coarse tremor, unsteady gait, slurred speech, and confusion over several days. Her GP recently started hydrochlorothiazide for hypertension. Most likely syndrome?","options":["Lithium toxicity","Serotonin syndrome","Neuroleptic malignant syndrome","Anticholinergic toxicity"],"answer":"Lithium toxicity","explanation":"Coarse tremor, ataxia, dysarthria, and confusion are hallmark lithium toxicity; a thiazide (like NSAIDs and ACEi/ARBs) reduces renal lithium clearance and raises the level. Toxicity begins around >1.5 mmol/L and is severe >2.0; hemodialysis is indicated for levels >4, or >2.5 with symptoms/renal failure.","meds":["lithium"],"disorder":"Lithium toxicity","difficulty":2,"tags":["interaction","monitoring"],"source":{"name":"Lithium monograph — toxicity/DDI","origin":"monograph"}},{"id":"vt_recognise_tyramine_crisis_1","stem":"A 47-year-old on phenelzine for treatment-resistant depression eats aged cheddar and cured salami at a party and within an hour develops a severe pounding occipital headache, blood pressure 220/125, palpitations, and neck stiffness. Most likely syndrome?","options":["Hypertensive crisis (tyramine reaction)","Serotonin syndrome","Neuroleptic malignant syndrome","Lithium toxicity"],"answer":"Hypertensive crisis (tyramine reaction)","explanation":"MAO inhibition prevents breakdown of dietary tyramine, causing a surge of norepinephrine release — the tyramine 'cheese reaction' with abrupt occipital headache and dangerous hypertension. It requires a strict low-tyramine diet (avoid aged cheese, cured/fermented meats, fermented soy, tap beer, and yeast extracts). It is a pressor crisis, not the neuromuscular picture of serotonin syndrome.","meds":["phenelzine"],"disorder":"Hypertensive crisis (tyramine reaction)","difficulty":2,"tags":["interaction"],"source":{"name":"Phenelzine monograph — tyramine reaction","origin":"monograph"}},{"id":"vt_ddi_fluvoxamine_clozapine_1a2_1","stem":"A patient stable on clozapine for treatment-resistant schizophrenia develops comorbid OCD and needs an SSRI. Which SSRI is the most dangerous to add because it will sharply raise the clozapine level and risk seizures/toxicity?","options":["Fluvoxamine","Sertraline","Escitalopram","Citalopram"],"answer":"Fluvoxamine","explanation":"Fluvoxamine is a potent CYP1A2 inhibitor and clozapine is a 1A2 substrate, so co-prescription can multiply clozapine levels and precipitate seizures, sedation, and cardiotoxicity. Sertraline, escitalopram, or citalopram are far safer 1A2-sparing choices. (The same 1A2 axis explains why stopping smoking also raises clozapine levels.)","meds":["fluvoxamine","clozapine","sertraline","escitalopram"],"disorder":"Schizophrenia","difficulty":2,"tags":["interaction"],"source":{"name":"Fluvoxamine/clozapine monograph — CYP1A2","origin":"monograph"}},{"id":"vt_ddi_maoi_meperidine_1","stem":"A 50-year-old maintained on phenelzine needs post-operative analgesia. The surgical team orders meperidine (pethidine). Shortly after the dose she becomes hyperthermic and agitated with clonus and rigidity. What syndrome has the MAOI + meperidine combination precipitated?","options":["Serotonin syndrome","Anticholinergic toxicity","Neuroleptic malignant syndrome","Hypertensive crisis (tyramine reaction)"],"answer":"Serotonin syndrome","explanation":"Meperidine has serotonergic activity and is explicitly contraindicated with MAOIs — the combination can cause fatal serotonin syndrome. This is a classic 'never' interaction: MAOIs must be kept away from meperidine, SSRIs/SNRIs/TCAs, tramadol, dextromethorphan, and linezolid, with a 14-day washout each way (5 weeks after fluoxetine).","meds":["phenelzine"],"disorder":"Serotonin syndrome","difficulty":2,"tags":["serotonin","interaction"],"source":{"name":"Phenelzine monograph — contraindicated combos","origin":"monograph"}},{"id":"vt_ddi_valproate_lamotrigine_1","stem":"A patient on lamotrigine maintenance for bipolar II is about to have a mood stabilizer added. Which agent roughly DOUBLES the lamotrigine level by inhibiting its glucuronidation, mandating that the lamotrigine dose be halved to reduce serious-rash risk?","options":["Valproate","Carbamazepine","Lithium","Gabapentin"],"answer":"Valproate","explanation":"Valproate inhibits lamotrigine glucuronidation and roughly doubles its level, sharply increasing the risk of Stevens–Johnson syndrome/TEN — so the lamotrigine dose is halved and titrated even more slowly. Carbamazepine does the opposite (induces glucuronidation and LOWERS lamotrigine); lithium and gabapentin do not have this pharmacokinetic interaction.","meds":["valproate","lamotrigine","carbamazepine","lithium"],"disorder":"Bipolar II disorder","difficulty":2,"tags":["interaction"],"source":{"name":"Lamotrigine/valproate monograph — DDI","origin":"monograph"}},{"id":"vt_ddi_carbamazepine_ocp_1","stem":"A 24-year-old woman with bipolar disorder using a combined oral contraceptive is started on a mood stabilizer, and three months later presents pregnant despite perfect pill adherence. Which drug most likely caused contraceptive failure through enzyme induction?","options":["Carbamazepine","Valproate","Lamotrigine","Lithium"],"answer":"Carbamazepine","explanation":"Carbamazepine is a strong CYP3A4 inducer and lowers estrogen/progestin levels, causing oral-contraceptive failure — a non-hormonal or higher-dose method is required. Valproate, lamotrigine, and lithium do not induce the pill's metabolism (indeed the estrogen in the pill LOWERS lamotrigine levels, the reverse direction).","meds":["carbamazepine","valproate","lamotrigine","lithium"],"disorder":"Bipolar disorder","difficulty":2,"tags":["interaction"],"source":{"name":"Carbamazepine monograph — 3A4 induction","origin":"monograph"}},{"id":"vt_ddi_carbamazepine_autoinduction_1","stem":"A man started on carbamazepine has a therapeutic level at week 1, but by week 4 — on the same dose, with good adherence — his level has fallen below range and seizures/mood symptoms return. Which property of carbamazepine explains this, requiring a level recheck at ~2–4 weeks?","options":["Carbamazepine","Valproate","Lamotrigine","Lithium"],"answer":"Carbamazepine","explanation":"Carbamazepine AUTO-induces its own CYP3A4 metabolism over the first weeks, so a level that was therapeutic can drop despite a stable dose — hence the standard recheck at ~2–4 weeks with dose adjustment. Valproate, lamotrigine, and lithium do not autoinduce in this way.","meds":["carbamazepine","valproate","lamotrigine","lithium"],"disorder":"Bipolar disorder","difficulty":2,"tags":["interaction","monitoring"],"source":{"name":"Carbamazepine monograph — autoinduction","origin":"monograph"}},{"id":"vt_ddi_clozapine_carbamazepine_1","stem":"A patient on clozapine develops trigeminal neuralgia and a consultant suggests a mood stabilizer/anticonvulsant. Which agent is specifically CONTRAINDICATED to combine with clozapine because of additive bone-marrow suppression and agranulocytosis risk?","options":["Carbamazepine","Valproate","Lithium","Lamotrigine"],"answer":"Carbamazepine","explanation":"Carbamazepine can itself cause agranulocytosis/aplastic anemia, so combining it with clozapine (already registry-monitored for neutropenia) is contraindicated — the marrow-suppression risk is additive, compounded by enzyme induction. Valproate, lithium (which can even raise the neutrophil count), or lamotrigine are used instead when a mood stabilizer is needed.","meds":["carbamazepine","clozapine","valproate","lithium"],"disorder":"Schizophrenia","difficulty":2,"tags":["agranulocytosis","interaction"],"source":{"name":"Clozapine monograph — contraindicated combos","origin":"monograph"}},{"id":"vt_overdose_most_lethal_tca_1","stem":"Four patients each ingest a two-week supply of their antidepressant. Which agent carries the HIGHEST risk of a fatal overdose from wide-QRS ventricular arrhythmia, seizures, and coma?","options":["Amitriptyline","Sertraline","Escitalopram","Fluoxetine"],"answer":"Amitriptyline","explanation":"TCAs like amitriptyline are among the most lethal antidepressants in overdose: sodium-channel blockade causes QRS widening and ventricular arrhythmia plus the 'three C's' (coma, convulsions, cardiotoxicity) and severe anticholinergic toxicity — treated with IV sodium bicarbonate. SSRIs (sertraline, escitalopram, fluoxetine) are comparatively safe in overdose, which is a major reason they are first-line.","meds":["amitriptyline","sertraline","escitalopram","fluoxetine"],"disorder":"Major depressive disorder","difficulty":1,"tags":["overdose"],"source":{"name":"TCA vs SSRI overdose lethality","origin":"authored"}},{"id":"vt_overdose_maoi_vs_ssri_1","stem":"A patient with treatment-resistant depression asks which of her possible antidepressants would be the most dangerous in overdose because of delayed (up to 12–24 h) hyperthermia, autonomic collapse, and a narrow margin. Which one?","options":["Phenelzine","Fluoxetine","Sertraline","Escitalopram"],"answer":"Phenelzine","explanation":"MAOI overdose (phenelzine) is dangerous and often DELAYED — agitation, hyperthermia, autonomic instability, and cardiovascular collapse can appear 12–24 h later, so a reassuring early picture is deceptive. This high lethality (shared with TCAs) contrasts sharply with the relative safety of SSRIs such as fluoxetine, sertraline, or escitalopram.","meds":["phenelzine","fluoxetine","sertraline","escitalopram"],"disorder":"Major depressive disorder","difficulty":2,"tags":["overdose"],"source":{"name":"Phenelzine monograph — overdose","origin":"monograph"}},{"id":"vt_overdose_barbiturate_vs_benzo_1","stem":"A patient co-ingests a sedative and presents with profound respiratory depression and coma. Which sedative-hypnotic has NO ceiling effect and the highest overdose lethality, is NOT reversed by flumazenil, and requires airway support and urinary alkalinization?","options":["Phenobarbital","Lorazepam","Diazepam","Zopiclone"],"answer":"Phenobarbital","explanation":"Barbiturates like phenobarbital have a narrow therapeutic index and no ceiling on CNS/respiratory depression, historically a common lethal overdose; management is supportive with multi-dose charcoal and urinary alkalinization, and flumazenil does NOT reverse them. This is the key contrast with benzodiazepines (lorazepam, diazepam) and z-drugs (zopiclone), which are far safer taken alone.","meds":["phenobarbital","lorazepam","diazepam","zopiclone"],"disorder":"Insomnia","difficulty":2,"tags":["overdose"],"source":{"name":"Phenobarbital monograph — overdose","origin":"monograph"}},{"id":"vt_overdose_lithium_dialysis_1","stem":"A patient with a very narrow-therapeutic-index psychotropic presents obtunded after an overdose; the toxicology team is considering hemodialysis. For which of these is overdose a medical emergency with hemodialysis indicated at a serum level >4 (or >2.5 with symptoms/renal failure)?","options":["Lithium","Sertraline","Lamotrigine","Quetiapine"],"answer":"Lithium","explanation":"Lithium has a narrow therapeutic index and its overdose is a medical emergency; hemodialysis is used for severe intoxication (level >4, or >2.5 with symptoms/renal failure) because dialysis efficiently clears the small ion. Sertraline, lamotrigine, and quetiapine overdoses are managed supportively and rarely require dialysis.","meds":["lithium","sertraline","lamotrigine","quetiapine"],"disorder":"Lithium toxicity","difficulty":2,"tags":["overdose","monitoring"],"source":{"name":"Lithium monograph — overdose/dialysis","origin":"monograph"}},{"id":"vt_pregnancy_valproate_avoid_1","stem":"A 27-year-old woman with bipolar I who plans to conceive is on a mood stabilizer. Which agent is the MOST teratogenic — causing neural-tube defects, the lowest childhood IQ, and increased autism — and should be avoided in people who can become pregnant?","options":["Valproate","Lamotrigine","Lithium","Carbamazepine"],"answer":"Valproate","explanation":"Valproate is the most teratogenic mood stabilizer: neural-tube defects (spina bifida), craniofacial/cardiac malformations, and dose-dependent neurodevelopmental harm (lowest IQ, increased autism). Carbamazepine also causes neural-tube defects but less severely overall; lamotrigine is a comparatively safer maintenance option, and lithium's main risk is the (lower-than-historically-taught) cardiac malformation.","meds":["valproate","lamotrigine","lithium","carbamazepine"],"disorder":"Bipolar I disorder","difficulty":1,"tags":["pregnancy"],"source":{"name":"Valproate monograph — teratogenicity","origin":"monograph"}},{"id":"vt_pregnancy_lithium_ebstein_1","stem":"A woman conceives while on maintenance therapy for bipolar disorder. First-trimester exposure to which agent is classically associated with Ebstein anomaly (a tricuspid-valve malformation), warranting fetal echocardiography?","options":["Lithium","Lamotrigine","Sertraline","Bupropion"],"answer":"Lithium","explanation":"First-trimester lithium is linked to Ebstein anomaly (tricuspid malformation), though the absolute risk is lower than historically taught; if continued, monitor levels closely (clearance rises in pregnancy then falls abruptly at delivery) and arrange fetal echocardiography. Lamotrigine, sertraline, and bupropion do not carry the Ebstein association.","meds":["lithium","lamotrigine","sertraline","bupropion"],"disorder":"Bipolar disorder","difficulty":2,"tags":["pregnancy"],"source":{"name":"Lithium monograph — pregnancy","origin":"monograph"}},{"id":"vt_pregnancy_safest_stabilizer_1","stem":"A pregnant woman with bipolar II needs mood-stabilizer maintenance. Which agent has the most reassuring reproductive-safety profile (no consistent major teratogenic signal) and is often preferred, keeping in mind that its levels fall in pregnancy and must be reduced postpartum?","options":["Lamotrigine","Valproate","Carbamazepine","Lithium"],"answer":"Lamotrigine","explanation":"Lamotrigine is comparatively pregnancy-safer with no consistent major teratogenic signal and is often the preferred maintenance stabilizer; its levels fall markedly during pregnancy (may need dose increases) and must be reduced postpartum to avoid toxicity. Valproate and carbamazepine cause neural-tube defects, and lithium carries the Ebstein risk.","meds":["lamotrigine","valproate","carbamazepine","lithium"],"disorder":"Bipolar II disorder","difficulty":2,"tags":["pregnancy"],"source":{"name":"Lamotrigine monograph — pregnancy","origin":"monograph"}},{"id":"vt_pregnancy_paroxetine_avoid_1","stem":"A woman planning pregnancy needs an antidepressant for recurrent MDD. Which SSRI is generally AVOIDED in the first trimester because of an association with fetal cardiac malformations (e.g., septal defects)?","options":["Paroxetine","Sertraline","Escitalopram","Fluoxetine"],"answer":"Paroxetine","explanation":"Paroxetine has been associated with cardiac malformations (e.g., septal defects) and is generally avoided in pregnancy when alternatives exist. Sertraline is a common perinatal first choice; escitalopram and fluoxetine are also reasonable — reflecting CANMAT perinatal guidance to prefer better-studied, lower-risk SSRIs.","meds":["paroxetine","sertraline","escitalopram","fluoxetine"],"disorder":"Major depressive disorder","difficulty":2,"tags":["pregnancy"],"source":{"name":"CANMAT perinatal 2024 / paroxetine monograph","origin":"canmat"}},{"id":"vt_monitor_clozapine_anc_1","stem":"Which antipsychotic requires mandatory, registry-enforced absolute neutrophil count monitoring — weekly for the first 6 months, then every 2 weeks to 12 months, then every 4 weeks — with discontinuation (and generally no rechallenge) if the ANC falls below 0.5 ×10⁹/L?","options":["Clozapine","Olanzapine","Risperidone","Quetiapine"],"answer":"Clozapine","explanation":"Only clozapine carries a mandatory ANC-monitoring registry because of its risk of agranulocytosis: weekly ×6 months, then q2 weeks to 12 months, then q4 weeks; severe neutropenia (ANC <0.5 ×10⁹/L) means discontinue and generally do not rechallenge. Olanzapine, risperidone, and quetiapine have no such hematologic monitoring requirement.","meds":["clozapine","olanzapine","risperidone","quetiapine"],"disorder":"Schizophrenia","difficulty":1,"tags":["agranulocytosis","monitoring"],"source":{"name":"Clozapine monograph — ANC monitoring","origin":"monograph"}},{"id":"vt_monitor_citalopram_qt_1","stem":"Which SSRI carries a dose-dependent QT-prolongation warning with a maximum-dose ceiling of 40 mg/day (20 mg/day in the elderly or hepatic impairment / CYP2C19 poor metabolizers), and the most QT risk in overdose?","options":["Citalopram","Sertraline","Fluoxetine","Paroxetine"],"answer":"Citalopram","explanation":"Citalopram has a dose-dependent QT-prolongation warning: cap at 40 mg/day (20 mg/day in the elderly, hepatic impairment, or CYP2C19 poor metabolizers), and it prolongs QT more than other SSRIs in overdose (get an ECG in significant ingestion). Its enantiomer escitalopram carries only a mild QT signal; sertraline, fluoxetine, and paroxetine lack this specific ceiling.","meds":["citalopram","sertraline","fluoxetine","paroxetine"],"disorder":"Major depressive disorder","difficulty":2,"tags":["qt","monitoring"],"source":{"name":"Citalopram monograph — QT warning","origin":"monograph"}},{"id":"vs_aud_first_line_naltrexone","stem":"A 44-year-old with alcohol use disorder is still drinking heavily and wants pharmacotherapy to cut down. He takes no opioids, and baseline LFTs and renal function are normal. Which agent is the best first-line choice?","options":["Naltrexone","Disulfiram","Acamprosate","Buprenorphine"],"answer":"Naltrexone","explanation":"Naltrexone is a first-line anti-craving agent that blunts the opioid-mediated reward of drinking and reduces heavy-drinking days; it can be started while the patient is still drinking. Disulfiram is an aversive, later-line option needing a highly motivated abstinent patient; acamprosate maintains abstinence best once already abstinent; buprenorphine treats opioid, not alcohol, use disorder.","meds":["naltrexone","disulfiram","acamprosate","buprenorphine"],"disorder":"Alcohol use disorder","difficulty":1,"tags":["first-line","craving"],"source":{"name":"CANMAT/CCSA alcohol use disorder","origin":"authored"}},{"id":"vs_aud_hepatic_acamprosate","stem":"A 58-year-old with alcohol use disorder has been abstinent for two weeks and now wants relapse-prevention pharmacotherapy. She has established alcoholic cirrhosis with elevated transaminases; renal function is normal. Which agent is safest and most appropriate?","options":["Acamprosate","Naltrexone","Disulfiram","Methadone"],"answer":"Acamprosate","explanation":"Acamprosate is renally excreted unchanged and is not hepatically metabolized, making it the preferred maintenance agent in significant liver disease. Naltrexone and disulfiram are both hepatotoxic and are cautioned/avoided with transaminitis; methadone is an opioid agonist irrelevant to alcohol use disorder.","meds":["acamprosate","naltrexone","disulfiram","methadone"],"disorder":"Alcohol use disorder","difficulty":2,"tags":["hepatic","special-population","maintenance"],"source":{"name":"Acamprosate monograph (renal clearance)","origin":"monograph"}},{"id":"vs_aud_disulfiram_reaction","stem":"A patient on medication for alcohol use disorder rinses with an alcohol-containing mouthwash and within minutes develops intense facial flushing, throbbing headache, nausea and vomiting, tachycardia and hypotension. Which reaction is this?","options":["Disulfiram–alcohol reaction","Serotonin syndrome","Anticholinergic toxicity","Precipitated opioid withdrawal"],"answer":"Disulfiram–alcohol reaction","explanation":"Disulfiram irreversibly inhibits aldehyde dehydrogenase; any alcohol exposure (including mouthwash, cough syrup, sauces) causes acetaldehyde accumulation with flushing, headache, nausea, tachycardia and hypotension. The picture is not serotonergic, anticholinergic, or opioid-withdrawal in nature.","meds":["disulfiram"],"disorder":"Alcohol use disorder","difficulty":2,"tags":["recognise-syndrome","interaction"],"source":{"name":"Disulfiram monograph","origin":"monograph"}},{"id":"vs_oud_first_line_bupnx","stem":"A 29-year-old with opioid use disorder presents to an outpatient clinic to start opioid agonist therapy. He is medically stable and adherence/safety are priorities. Which agent is recommended as first-line?","options":["Buprenorphine / Naloxone","Methadone","Naltrexone","Naloxone"],"answer":"Buprenorphine / Naloxone","explanation":"CRISM guidance favours buprenorphine/naloxone as first-line opioid agonist therapy because the partial agonist has a ceiling on respiratory depression and a far safer overdose profile than methadone. Methadone is a second-line full agonist; naltrexone is an antagonist requiring prior abstinence; naloxone is an acute rescue drug, not maintenance.","meds":["buprenorphine_naloxone","methadone","naltrexone","naloxone"],"disorder":"Opioid use disorder","difficulty":1,"tags":["first-line","oat"],"source":{"name":"CRISM national OAT guideline","origin":"authored"}},{"id":"vs_oud_precipitated_withdrawal","stem":"A patient who used a full-agonist opioid a few hours earlier is given a first dose of buprenorphine before objective withdrawal has appeared. Within 30 minutes he becomes acutely diaphoretic, nauseated, and markedly worse than before. What has happened?","options":["Precipitated opioid withdrawal","Opioid overdose","Serotonin syndrome","Disulfiram–alcohol reaction"],"answer":"Precipitated opioid withdrawal","explanation":"Buprenorphine's high mu-receptor affinity but low intrinsic activity displaces the full agonist and abruptly drops receptor activation, precipitating withdrawal when started too early. Induction should wait for objective withdrawal (e.g. COWS) or use a micro-dosing protocol; this is the opposite of overdose and is not serotonergic.","meds":["buprenorphine","buprenorphine_naloxone"],"disorder":"Opioid use disorder","difficulty":2,"tags":["recognise-syndrome","precipitated-withdrawal","induction"],"source":{"name":"Buprenorphine induction (COWS)","origin":"authored"}},{"id":"vs_oud_overdose_rescue","stem":"A man is found unresponsive with a respiratory rate of 6, pinpoint pupils, and drug paraphernalia nearby. Which agent is the immediate pharmacologic rescue?","options":["Naloxone","Naltrexone","Methadone","Buprenorphine"],"answer":"Naloxone","explanation":"Naloxone is a short-acting opioid antagonist that rapidly reverses opioid-induced respiratory depression; watch for re-narcotization as it wears off. Naltrexone is a maintenance antagonist (not for acute rescue), while methadone and buprenorphine are agonists that would worsen the overdose.","meds":["naloxone","naltrexone","methadone","buprenorphine"],"disorder":"Opioid use disorder","difficulty":1,"tags":["overdose","rescue"],"source":{"name":"Naloxone monograph","origin":"monograph"}},{"id":"vs_oud_methadone_qt","stem":"A patient on methadone maintenance has his dose escalated above 100 mg/day and is also started on a QT-prolonging antibiotic. He develops syncope; ECG shows a markedly prolonged QTc. Which methadone-related complication does this represent?","options":["QT prolongation / torsades de pointes","Serotonin syndrome","Neuroleptic malignant syndrome","Opioid withdrawal"],"answer":"QT prolongation / torsades de pointes","explanation":"Methadone causes dose-dependent QT prolongation and torsades, so an ECG is obtained at baseline, around 30 days, and periodically, especially above 100 mg/day or with additive QT drugs. This is a cardiac-conduction event, not a serotonergic, dopaminergic (NMS), or withdrawal phenomenon.","meds":["methadone"],"disorder":"Opioid use disorder","difficulty":3,"tags":["qt","monitoring","recognise-syndrome"],"source":{"name":"Methadone monograph (QT/ECG)","origin":"monograph"}},{"id":"vs_oud_naltrexone_washout","stem":"A patient with opioid use disorder has completed a supervised withdrawal and has been opioid-free for 10 days. He prefers a non-agonist agent that will block relapse without any abuse potential. Which is appropriate?","options":["Naltrexone","Methadone","Buprenorphine / Naloxone","Acamprosate"],"answer":"Naltrexone","explanation":"Naltrexone is an opioid antagonist for the detoxified patient; it requires roughly 7–10 opioid-free days first, otherwise it precipitates withdrawal, and the extended-release depot aids adherence. Methadone and buprenorphine/naloxone are agonist therapies; acamprosate is for alcohol, not opioid, use disorder.","meds":["naltrexone","methadone","buprenorphine_naloxone","acamprosate"],"disorder":"Opioid use disorder","difficulty":2,"tags":["washout","switching","relapse-prevention"],"source":{"name":"Naltrexone monograph (opioid-free interval)","origin":"monograph"}},{"id":"vs_tobacco_varenicline_first","stem":"A motivated 50-year-old smoker with no psychiatric or seizure history wants the single most effective pharmacotherapy for smoking cessation. Which do you recommend?","options":["Varenicline","Bupropion","Clonidine","Naltrexone"],"answer":"Varenicline","explanation":"Varenicline, an α4β2 nicotinic partial agonist, is the most effective single agent for smoking cessation and is started about a week before the quit date (nausea and vivid dreams are the hallmark effects). Bupropion is effective but less so, clonidine is second-line, and naltrexone is not a cessation aid.","meds":["varenicline","bupropion","clonidine","naltrexone"],"disorder":"Tobacco use disorder","difficulty":1,"tags":["first-line"],"source":{"name":"Varenicline monograph / EAGLES","origin":"monograph"}},{"id":"vs_tobacco_bupropion_dual","stem":"A 40-year-old smoker also has untreated major depression and no seizure or eating disorder history. He would prefer a single medication that helps both his mood and quitting smoking. Which is the best choice?","options":["Bupropion","Varenicline","Escitalopram","Clonidine"],"answer":"Bupropion","explanation":"Bupropion treats major depression and is an established smoking-cessation aid (marketed as Zyban), making it the efficient single agent here — provided there is no seizure disorder or eating disorder, in which it is contraindicated. Varenicline aids cessation but not depression, escitalopram treats depression but not smoking, and clonidine is only a second-line cessation option.","meds":["bupropion","varenicline","escitalopram","clonidine"],"disorder":"Tobacco use disorder","difficulty":2,"tags":["dual-purpose","depression"],"source":{"name":"Bupropion monograph (MDD + Zyban)","origin":"monograph"}},{"id":"vs_adhd_stimulant_first_line","stem":"A healthy 24-year-old with newly diagnosed ADHD, no cardiac disease and no substance-use concerns, wants the most effective pharmacotherapy. Which agent class is first-line?","options":["Lisdexamfetamine","Atomoxetine","Guanfacine XR","Clonidine"],"answer":"Lisdexamfetamine","explanation":"Stimulants are the most effective, first-line treatment for ADHD in patients without a contraindication; lisdexamfetamine is a stimulant (a prodrug of dextroamphetamine). Atomoxetine, guanfacine XR, and clonidine are non-stimulants reserved mainly for patients who cannot tolerate, misuse, or fail stimulants.","meds":["lisdexamfetamine","atomoxetine","guanfacine","clonidine"],"disorder":"ADHD","difficulty":1,"tags":["first-line","stimulant"],"source":{"name":"CADDRA ADHD guideline","origin":"authored"}},{"id":"vs_adhd_misuse_atomoxetine","stem":"A 30-year-old with ADHD has an active stimulant use disorder and a documented history of diverting medication. He needs effective ADHD treatment with the lowest misuse and diversion risk. Which agent is preferred?","options":["Atomoxetine","Dextroamphetamine","Methylphenidate","Mixed Amphetamine Salts"],"answer":"Atomoxetine","explanation":"Atomoxetine is a non-controlled selective norepinephrine reuptake inhibitor with no abuse or diversion potential, making it preferred when misuse risk is high (it takes several weeks to work). Dextroamphetamine, methylphenidate, and mixed amphetamine salts are all controlled stimulants with abuse liability.","meds":["atomoxetine","dextroamphetamine","methylphenidate","amphetamine_salts"],"disorder":"ADHD","difficulty":2,"tags":["misuse","special-population"],"source":{"name":"Atomoxetine monograph (non-controlled NRI)","origin":"monograph"}},{"id":"vs_adhd_cardiac_avoid_stimulant","stem":"A 15-year-old with ADHD is found to have hypertrophic cardiomyopathy on cardiology work-up. Which ADHD medication is the most clearly contraindicated?","options":["Lisdexamfetamine","Atomoxetine","Guanfacine XR","Clonidine"],"answer":"Lisdexamfetamine","explanation":"Stimulants such as lisdexamfetamine carry a risk of sudden cardiac death in patients with serious structural heart disease and should be avoided in hypertrophic cardiomyopathy. The non-stimulants are comparatively safer here — atomoxetine raises HR/BP modestly, and the α2 agonists tend to lower them — but the stimulant is the one to avoid outright.","meds":["lisdexamfetamine","atomoxetine","guanfacine","clonidine"],"disorder":"ADHD","difficulty":2,"tags":["cardiac","contraindication"],"source":{"name":"Stimulant cardiac warnings","origin":"monograph"}},{"id":"vs_adhd_maoi_guanfacine","stem":"An adult with treatment-refractory depression is stable on phenelzine and now needs treatment for comorbid ADHD. Which agent can be used without risking a hypertensive crisis?","options":["Guanfacine XR","Methylphenidate","Lisdexamfetamine","Atomoxetine"],"answer":"Guanfacine XR","explanation":"Stimulants and atomoxetine are contraindicated with an MAOI or within 14 days of stopping one because of hypertensive-crisis risk. The α2A agonist guanfacine XR carries no MAOI-washout requirement and can be used, with monitoring for bradycardia and hypotension.","meds":["guanfacine","methylphenidate","lisdexamfetamine","atomoxetine","phenelzine"],"disorder":"ADHD","difficulty":2,"tags":["maoi","interaction"],"source":{"name":"Stimulant/atomoxetine MAOI washout","origin":"monograph"}},{"id":"vs_adhd_mechanism_amphetamine","stem":"On an oral board, you are asked which ADHD stimulant works primarily by driving presynaptic RELEASE of dopamine and norepinephrine (reversing the transporters), rather than by pure reuptake blockade. Which is it?","options":["Dextroamphetamine","Methylphenidate","Atomoxetine","Guanfacine XR"],"answer":"Dextroamphetamine","explanation":"Amphetamines such as dextroamphetamine enter the neuron and trigger vesicular release of dopamine and norepinephrine (and block reuptake). Methylphenidate is a pure reuptake blocker, atomoxetine is a selective NE reuptake inhibitor, and guanfacine is a postsynaptic α2A agonist — none of which drive presynaptic release.","meds":["dextroamphetamine","methylphenidate","atomoxetine","guanfacine"],"disorder":"ADHD","difficulty":3,"tags":["mechanism"],"source":{"name":"Stimulant pharmacology","origin":"authored"}},{"id":"vs_insomnia_elderly_dora","stem":"A 78-year-old with chronic insomnia and a prior fall wants ongoing pharmacotherapy. You want to minimize fall risk and next-day impairment. Which agent is the most appropriate?","options":["Daridorexant","Zopiclone","Temazepam","Flurazepam"],"answer":"Daridorexant","explanation":"Daridorexant is a dual orexin antagonist with a short half-life and the least next-day impairment, avoiding the GABA-mediated fall/confusion risk of the other options. Benzodiazepine hypnotics (temazepam, flurazepam) and Z-drugs (zopiclone) are Beers-listed to avoid in older adults, and flurazepam's long-lived active metabolite accumulates.","meds":["daridorexant","zopiclone","temazepam","flurazepam"],"disorder":"Insomnia","difficulty":2,"tags":["elderly","beers"],"source":{"name":"Beers criteria / daridorexant monograph","origin":"monograph"}},{"id":"vs_insomnia_zdrug_complex_behaviour","stem":"Two weeks after starting a hypnotic, a patient's partner reports she has driven the car and prepared food while asleep, with no memory of these events the next morning. Which drug is the classic cause of this?","options":["Zolpidem","Melatonin","Ramelteon","Buspirone"],"answer":"Zolpidem","explanation":"Z-drugs such as zolpidem carry a boxed/serious warning for complex sleep behaviours — sleep-driving, sleep-eating and sleep-walking with anterograde amnesia — and should be discontinued if these occur. Melatonin, the melatonin agonist ramelteon, and the anxiolytic buspirone are not characteristically implicated.","meds":["zolpidem","melatonin","ramelteon","buspirone"],"disorder":"Insomnia","difficulty":2,"tags":["complex-sleep-behaviour","z-drug"],"source":{"name":"Zolpidem monograph (boxed warning)","origin":"monograph"}},{"id":"vs_insomnia_ramelteon_fluvoxamine","stem":"A patient stabilized on fluvoxamine for OCD now needs a hypnotic for sleep-onset insomnia. Which agent is contraindicated because of a major CYP1A2 interaction?","options":["Ramelteon","Zopiclone","Trazodone","Temazepam"],"answer":"Ramelteon","explanation":"Fluvoxamine is a potent CYP1A2 inhibitor that dramatically raises ramelteon (and melatonin) levels, so the combination is contraindicated. Zopiclone, trazodone, and temazepam are not CYP1A2-dependent in the same way and are not contraindicated with fluvoxamine on that basis.","meds":["ramelteon","fluvoxamine","zopiclone","trazodone","temazepam"],"disorder":"Insomnia","difficulty":3,"tags":["interaction","cyp1a2"],"source":{"name":"Ramelteon monograph (fluvoxamine)","origin":"monograph"}},{"id":"vs_insomnia_maintenance_doxepin","stem":"A 72-year-old has sleep-MAINTENANCE insomnia with frequent early-morning awakenings and wants a non-controlled option with a low fall/amnesia risk. Which is the best choice?","options":["Doxepin","Triazolam","Zolpidem","Flurazepam"],"answer":"Doxepin","explanation":"At low dose (3–6 mg) doxepin acts as a selective H1 antihistamine for sleep maintenance, is non-controlled, and is comparatively better studied in older adults. Triazolam causes marked amnesia and early rebound, and zolpidem and flurazepam are on Beers avoid lists for older adults.","meds":["doxepin","triazolam","zolpidem","flurazepam"],"disorder":"Insomnia","difficulty":3,"tags":["elderly","maintenance"],"source":{"name":"Low-dose doxepin monograph","origin":"monograph"}},{"id":"vs_insomnia_depression_mirtazapine","stem":"A 60-year-old with major depression also has prominent insomnia, poor appetite and weight loss. Which single agent best addresses all of these together?","options":["Mirtazapine","Trazodone","Zopiclone","Bupropion"],"answer":"Mirtazapine","explanation":"Mirtazapine treats depression while its sedating (especially at low dose) and appetite-stimulating properties target insomnia, poor appetite and weight loss in one agent. Trazodone and zopiclone address only sleep, and bupropion is activating and can worsen insomnia.","meds":["mirtazapine","trazodone","zopiclone","bupropion"],"disorder":"Major depressive disorder","difficulty":2,"tags":["insomnia","depression","special-population"],"source":{"name":"Mirtazapine monograph","origin":"monograph"}}];
